## Common patterns

### Form validation

Validate radio input selection and display error messages:

```jsx live-dev
const App = () => {
  const [value, setValue] = useState<string | undefined>(undefined);
  const [error, setError] = useState<string | undefined>(undefined);
  const [touched, setTouched] = useState(false);

  const handleChange = (newValue: string) => {
    setValue(newValue);
    setError(undefined);
  };

  const handleBlur = () => {
    setTouched(true);
    if (!value) {
      setError('Please select an option');
    }
  };

  const handleSubmit = () => {
    if (!value) {
      setError('Please select an option');
      setTouched(true);
    }
  };

  return (
    <Stack direction="column" gap="400">
      <FormField.Root isInvalid={!!(error && touched)}>
        <FormField.Label>Select an option</FormField.Label>
        <FormField.Input>
          <RadioInput.Root
            name="validation-example"
            value={value}
            onChange={handleChange}
            onBlur={handleBlur}
            isInvalid={!!(error && touched)}
            aria-label="Option selection"
          >
            <RadioInput.Option value="option1">Option 1</RadioInput.Option>
            <RadioInput.Option value="option2">Option 2</RadioInput.Option>
            <RadioInput.Option value="option3">Option 3</RadioInput.Option>
          </RadioInput.Root>
        </FormField.Input>
        {touched && error && (
          <FormField.Error>{error}</FormField.Error>
        )}
      </FormField.Root>
      <Button onPress={handleSubmit}>Submit</Button>
      {value && !error && (
        <Text fontSize="sm" color="positive.9">
          Successfully selected: {value}
        </Text>
      )}
    </Stack>
  );
}
```

### Conditional rendering based on selection

Show or hide content based on the selected radio option:

```jsx live-dev
const App = () => {
  const [value, setValue] = useState<string | undefined>(undefined);

  return (
    <Stack direction="column" gap="400">
      <RadioInput.Root
        name="conditional-example"
        value={value}
        onChange={setValue}
      >
        <RadioInput.Option value="yes">Yes, I agree</RadioInput.Option>
        <RadioInput.Option value="no">No, I disagree</RadioInput.Option>
      </RadioInput.Root>

      {value === 'yes' && (
        <Text fontSize="sm" color="positive.9">
          Thank you for agreeing!
        </Text>
      )}

      {value === 'no' && (
        <Text fontSize="sm" color="critical.9">
          Please let us know why you disagree.
        </Text>
      )}
    </Stack>
  );
}
```

## Testing your implementation

These examples demonstrate how to test your implementation when using RadioInput in your application. As the component's internal functionality is already tested by Nimbus, these patterns help you verify your integration and application-specific logic.

### Basic Rendering Tests

Verify the component renders with expected elements

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { RadioInput, NimbusProvider } from "@commercetools/nimbus";

describe("RadioInput - Basic rendering", () => {
  it("renders radio group with options", () => {
    render(
      <NimbusProvider>
        <RadioInput.Root name="test-radio" aria-label="Test selection">
          <RadioInput.Option value="option1">Option 1</RadioInput.Option>
          <RadioInput.Option value="option2">Option 2</RadioInput.Option>
        </RadioInput.Root>
      </NimbusProvider>
    );

    expect(screen.getByRole("radiogroup")).toBeInTheDocument();
    expect(
      screen.getByRole("radio", { name: /option 1/i })
    ).toBeInTheDocument();
    expect(
      screen.getByRole("radio", { name: /option 2/i })
    ).toBeInTheDocument();
  });

  it("renders with default value selected", () => {
    render(
      <NimbusProvider>
        <RadioInput.Root
          name="test-radio"
          defaultValue="option1"
          aria-label="Test selection"
        >
          <RadioInput.Option value="option1">Option 1</RadioInput.Option>
          <RadioInput.Option value="option2">Option 2</RadioInput.Option>
        </RadioInput.Root>
      </NimbusProvider>
    );

    expect(screen.getByRole("radio", { name: /option 1/i })).toBeChecked();
    expect(screen.getByRole("radio", { name: /option 2/i })).not.toBeChecked();
  });
});
```

### Interaction Tests

Test user interactions with the component

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { RadioInput, NimbusProvider } from "@commercetools/nimbus";

describe("RadioInput - Interactions", () => {
  it("calls onChange when option is selected", async () => {
    const user = userEvent.setup();
    const handleChange = vi.fn();

    render(
      <NimbusProvider>
        <RadioInput.Root
          name="test-radio"
          onChange={handleChange}
          aria-label="Test selection"
        >
          <RadioInput.Option value="option1">Option 1</RadioInput.Option>
          <RadioInput.Option value="option2">Option 2</RadioInput.Option>
        </RadioInput.Root>
      </NimbusProvider>
    );

    const option2 = screen.getByRole("radio", { name: /option 2/i });
    await user.click(option2);

    expect(handleChange).toHaveBeenCalledWith("option2");
  });

  it("allows only one option to be selected at a time", async () => {
    const user = userEvent.setup();

    render(
      <NimbusProvider>
        <RadioInput.Root
          name="test-radio"
          defaultValue="option1"
          aria-label="Test selection"
        >
          <RadioInput.Option value="option1">Option 1</RadioInput.Option>
          <RadioInput.Option value="option2">Option 2</RadioInput.Option>
          <RadioInput.Option value="option3">Option 3</RadioInput.Option>
        </RadioInput.Root>
      </NimbusProvider>
    );

    const option1 = screen.getByRole("radio", { name: /option 1/i });
    const option2 = screen.getByRole("radio", { name: /option 2/i });
    const option3 = screen.getByRole("radio", { name: /option 3/i });

    expect(option1).toBeChecked();
    expect(option2).not.toBeChecked();
    expect(option3).not.toBeChecked();

    await user.click(option2);

    await waitFor(() => {
      expect(option1).not.toBeChecked();
      expect(option2).toBeChecked();
      expect(option3).not.toBeChecked();
    });
  });

  it("supports keyboard navigation with arrow keys", async () => {
    const user = userEvent.setup();

    render(
      <NimbusProvider>
        <RadioInput.Root name="test-radio" aria-label="Test selection">
          <RadioInput.Option value="option1">Option 1</RadioInput.Option>
          <RadioInput.Option value="option2">Option 2</RadioInput.Option>
        </RadioInput.Root>
      </NimbusProvider>
    );

    const option1 = screen.getByRole("radio", { name: /option 1/i });
    const option2 = screen.getByRole("radio", { name: /option 2/i });

    // Tab to focus the first option
    await user.tab();
    expect(option1).toHaveFocus();

    // Use arrow key to navigate to next option
    await user.keyboard("{ArrowDown}");
    expect(option2).toHaveFocus();

    // Select with Space
    await user.keyboard(" ");
    expect(option2).toBeChecked();
  });
});
```

### Testing Disabled State

Test disabled state behavior

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { RadioInput, NimbusProvider } from "@commercetools/nimbus";

describe("RadioInput - Disabled state", () => {
  it("prevents interaction when disabled", async () => {
    const user = userEvent.setup();
    const handleChange = vi.fn();

    render(
      <NimbusProvider>
        <RadioInput.Root
          name="test-radio"
          isDisabled
          onChange={handleChange}
          aria-label="Test selection"
        >
          <RadioInput.Option value="option1">Option 1</RadioInput.Option>
          <RadioInput.Option value="option2">Option 2</RadioInput.Option>
        </RadioInput.Root>
      </NimbusProvider>
    );

    const radioGroup = screen.getByRole("radiogroup");
    expect(radioGroup).toHaveAttribute("aria-disabled", "true");

    const option1 = screen.getByRole("radio", { name: /option 1/i });
    await user.click(option1);

    expect(handleChange).not.toHaveBeenCalled();
  });

  it("does not receive focus when disabled", async () => {
    const user = userEvent.setup();

    render(
      <NimbusProvider>
        <RadioInput.Root
          name="test-radio"
          isDisabled
          aria-label="Test selection"
        >
          <RadioInput.Option value="option1">Option 1</RadioInput.Option>
        </RadioInput.Root>
      </NimbusProvider>
    );

    await user.tab();
    const option1 = screen.getByRole("radio", { name: /option 1/i });
    expect(option1).not.toHaveFocus();
  });
});
```

